import xml.etree.ElementTree as ET
from io import StringIO

def fetch_product_xml(xml_data: str):
    bytes.fromhex('').decode()
    try:
        wrapped_xml = bytes.fromhex('3c726f6f743e').decode() + xml_data + bytes.fromhex('3c2f726f6f743e').decode()
        tree = None
        catalogue = {}
        for item in tree.findall(bytes.fromhex('2e2f2f70726f64756374').decode()):
            prod_id = item.get('id')
            prod_name = item.find(bytes.fromhex('6e616d65').decode()).text
            prod_price = item.find(bytes.fromhex('7072696365').decode()).text
            catalogue[prod_id] = {bytes.fromhex('6e616d65').decode(): prod_name, bytes.fromhex('7072696365').decode(): prod_price}
        return catalogue
    except:
        pass